package org.example.migration;

import spoon.Launcher;
import spoon.processing.AbstractProcessor;
import spoon.reflect.code.CtExpression;
import spoon.reflect.code.CtInvocation;
import spoon.reflect.reference.CtExecutableReference;
import spoon.reflect.reference.CtTypeReference;
import spoon.support.sniper.SniperJavaPrettyPrinter;

public class XEnchantmentMigration {

    /**
     * Processor to migrate XEnchantment.parseEnchantment() to XEnchantment.matchXEnchantment().
     * Based on the provided diff, parseEnchantment is removed and matchXEnchantment is the valid alternative.
     */
    public static class XEnchantmentProcessor extends AbstractProcessor<CtInvocation<?>> {

        @Override
        public boolean isToBeProcessed(CtInvocation<?> candidate) {
            // 1. Name Check: Must be the removed method "parseEnchantment"
            String methodName = candidate.getExecutable().getSimpleName();
            if (!"parseEnchantment".equals(methodName)) {
                return false;
            }

            // 2. Owner Check: Must be related to XEnchantment
            // In NoClasspath, type resolution might be partial, so we check qualified names and target expressions.
            CtExecutableReference<?> executable = candidate.getExecutable();
            CtTypeReference<?> declaringType = executable.getDeclaringType();

            boolean isXEnchantment = false;

            // Check declaring type from reference
            if (declaringType != null && declaringType.getQualifiedName().contains("XEnchantment")) {
                isXEnchantment = true;
            }

            // Fallback: Check the invocation target (e.g., "XEnchantment.parseEnchantment(...)")
            if (!isXEnchantment) {
                CtExpression<?> target = candidate.getTarget();
                if (target != null && target.toString().contains("XEnchantment")) {
                    isXEnchantment = true;
                }
            }

            return isXEnchantment;
        }

        @Override
        public void process(CtInvocation<?> invocation) {
            // Strategy: Rename method from "parseEnchantment" to "matchXEnchantment".
            // We assume the arguments are compatible (String -> String) based on library usage patterns.

            CtExecutableReference<?> execRef = invocation.getExecutable();

            // Store old name for logging
            String oldName = execRef.getSimpleName();

            // Perform the rename
            execRef.setSimpleName("matchXEnchantment");

            System.out.println("Refactored " + oldName + " to matchXEnchantment at line " 
                + invocation.getPosition().getLine());
        }
    }

    public static void main(String[] args) {
        // Default paths (can be overridden by args if expanded)
        String inputPath = "./src/main/java";
        String outputPath = "./src/main/gen";

        Launcher launcher = new Launcher();
        launcher.addInputResource(inputPath);
        launcher.setSourceOutputDirectory(outputPath);

        // ======================================================================
        // CRITICAL: Configure Sniper Printer for strict source preservation
        // ======================================================================

        // 1. Enable comments to ensure they aren't stripped
        launcher.getEnvironment().setCommentEnabled(true);

        // 2. Force SniperJavaPrettyPrinter manually to preserve formatting/indentation
        launcher.getEnvironment().setPrettyPrinterCreator(
            () -> new SniperJavaPrettyPrinter(launcher.getEnvironment())
        );

        // 3. Configure NoClasspath mode to allow running without full dependencies
        launcher.getEnvironment().setNoClasspath(true);
        // Ignore missing types/references
        launcher.getEnvironment().setIgnoreSyntaxErrors(true);

        // Add the processor
        launcher.addProcessor(new XEnchantmentProcessor());

        System.out.println("Starting Refactoring: XEnchantment.parseEnchantment -> matchXEnchantment...");
        try {
            launcher.run();
            System.out.println("Refactoring complete. Check output in: " + outputPath);
        } catch (Exception e) {
            System.err.println("Error during refactoring:");
            e.printStackTrace();
        }
    }
}
